import React, { useState } from "react";
import { theme, Card, Typography, Space } from "antd";
import MapView from "./components/MapView";
import StatusGrid from "./components/StatusGrid";
import DetailPanel from "./components/DetailPanel";
import { mockStorages, StorageInfo } from "./data/mockData";
import { useI18n } from "@/framework/i18n/hooks";

const { useToken } = theme;
const { Title, Text } = Typography;

export default function Dashboard() {
  const { token } = useToken();
  const { t } = useI18n(["storageLocker", "platform", "common"]);
  const [selectedLocker, setSelectedLocker] = useState<StorageInfo | null>(null);

  const handleSelect = (item: StorageInfo) => {
    setSelectedLocker((prev) => (prev?.id === item.id ? null : item));
  };

  return (
    <div 
      className="storage-locker-dashboard"
      style={{ 
        height: "100%", 
        display: "flex", 
        flexDirection: "column", 
        gap: 16, 
        padding: 16,
        background: token.colorBgLayout,
        overflow: "hidden"
      }}
    >
      {/* Header Area */}
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
        <Space direction="vertical" size={0}>
          <Title level={4} style={{ margin: 0 }}>{t("storageLocker:dashboard.mainTitle")}</Title>
          <Text type="secondary" style={{ fontSize: 13 }}>{t("storageLocker:dashboard.mainDesc")}</Text>
        </Space>
      </div>

      <div style={{ flex: 1, display: "flex", gap: 16, minHeight: 0, overflow: "hidden" }}>
        {/* Left Side: Map and List */}
        <div style={{ flex: 3, display: "flex", flexDirection: "column", gap: 16, minWidth: 0 }}>
          {/* Map Section */}
          <Card 
            size="small" 
            title={t("storageLocker:dashboard.mapTitle")}
            style={{ 
              flex: 2, 
              borderRadius: token.borderRadiusLG, 
              overflow: "hidden", 
              boxShadow: "0 4px 12px rgba(0,0,0,0.12)" 
            }}
            bodyStyle={{ padding: 0, height: "100%" }}
          >
            <MapView items={mockStorages} selectedId={selectedLocker?.id} onSelect={handleSelect} />
          </Card>

          {/* List Section */}
          <Card 
            size="small" 
            title={t("storageLocker:dashboard.statusListTitle")}
            style={{ 
              flex: 1, 
              borderRadius: token.borderRadiusLG, 
              overflow: "hidden",
            }}
            bodyStyle={{ padding: 0, overflow: "auto" }}
          >
            <StatusGrid 
              items={mockStorages} 
              selectedId={selectedLocker?.id} 
              onSelect={handleSelect} 
            />
          </Card>
        </div>

        {/* Right Side: Detail Information (Conditionally shown) */}
        <div style={{ flex: 1, display: "flex", flexDirection: "column", minWidth: 320 }}>
          <Card 
            size="small" 
            title={t("storageLocker:dashboard.detailTitle")}
            style={{ 
              height: "100%", 
              borderRadius: token.borderRadiusLG,
              display: "flex",
              flexDirection: "column"
            }}
            bodyStyle={{ flex: 1, overflow: "auto" }}
          >
            <DetailPanel item={selectedLocker} onRefresh={handleSelect} />
          </Card>
        </div>
      </div>
    </div>
  );
}
